components.ChaseListPanel:
export default function ChaseListPanel() {
  const [clients, setClients] = useState([]);
  const [deadlines, setDeadlines] = useState([]);
  const [selected, setSelected] = useState(null);
  const [message, setMessage] = useState("");
  const [phase, setPhase] = useState("idle");
  const [sent, setSent] = useState({});

  useEffect(() => {
    Promise.all([
      tools.host_listClients({ filter: "missing_docs" }),
      tools.host_listDeadlines(),
    ]).then(([cl, dl]) => {
      const deadlineMap = {};
      (dl.data || dl || []).forEach((d) => { deadlineMap[d.id] = d; });
      const rows = (cl.data || cl || []).map((c) => {
        const dl = deadlineMap[c.id] || {};
        const missing = c.documentsOutstanding ?? (c.documents ? c.documents.filter(d => d.status === "missing" || d.status === "needs_review").length : 0);
        const total = c.documentsTotal ?? (c.documents ? c.documents.length : 0);
        const deadline = c.filingDeadline || dl.filingDeadline || null;
        const daysLeft = deadline ? Math.ceil((new Date(deadline) - new Date("2026-07-21")) / 86400000) : null;
        return { ...c, missing, total, deadline, daysLeft };
      }).sort((a, b) => {
        const urgencyA = (a.daysLeft !== null ? a.daysLeft : 9999) - (a.missing * 100);
        const urgencyB = (b.daysLeft !== null ? b.daysLeft : 9999) - (b.missing * 100);
        return urgencyA - urgencyB;
      });
      setClients(rows);
      setDeadlines(dl.data || dl || []);
    });
  }, []);

  const open = (c) => {
    setSelected(c);
    setMessage("");
    setPhase("idle");
  };
  const close = () => { setSelected(null); setPhase("idle"); };

  const send = async () => {
    if (!message.trim() || !selected) return;
    setPhase("sending");
    const result = await tools.host_sendClientMessage({
      id: selected.id,
      body: { body: message, author: "Firm" },
    });
    setPhase(result && result.status === "pending-approval" ? "awaiting" : "sent");
    if (result && result.status !== "pending-approval") {
      setSent((prev) => ({ ...prev, [selected.id]: true }));
    }
  };

  const urgencyVariant = (c) => {
    if (c.daysLeft !== null && c.daysLeft <= 7) return "overdue";
    if (c.missing > 0) return "missing";
    return "neutral";
  };

  const daysLabel = (daysLeft) => {
    if (daysLeft === null) return "—";
    if (daysLeft < 0) return `${Math.abs(daysLeft)}d overdue`;
    if (daysLeft === 0) return "Due today";
    if (daysLeft === 1) return "Tomorrow";
    if (daysLeft <= 7) return `${daysLeft}d left`;
    return `${daysLeft}d`;
  };

  const tokens = {
    bg: "var(--vendo-color-background)",
    surface: "var(--vendo-color-surface)",
    text: "var(--vendo-color-text)",
    muted: "var(--vendo-color-muted)",
    accent: "var(--vendo-color-accent)",
    accentText: "var(--vendo-color-accent-text)",
    danger: "var(--vendo-color-danger)",
    border: "var(--vendo-color-border)",
    font: "var(--vendo-font-family)",
    radiusSm: "var(--vendo-radius-small)",
    radiusMd: "var(--vendo-radius-medium)",
  };

  return (
    <div style={{ fontFamily: tokens.font, color: tokens.text }}>
      {clients.length === 0 && (
        <div style={{ padding: 24, color: tokens.muted, textAlign: "center", fontSize: 14 }}>
          No clients with outstanding documents — nothing to chase this week.
        </div>
      )}

      {clients.length > 0 && (
        <table style={{ width: "100%", borderCollapse: "collapse", fontSize: 14 }}>
          <thead>
            <tr style={{ borderBottom: `1px solid ${tokens.border}` }}>
              {["Client", "Missing", "Progress", "Deadline", "Status", ""].map((h) => (
                <th key={h} style={{ padding: "8px 12px", textAlign: h === "Missing" || h === "" ? "center" : "left", fontWeight: 600, color: tokens.muted, fontSize: 12, letterSpacing: "0.03em" }}>{h}</th>
              ))}
            </tr>
          </thead>
          <tbody>
            {clients.map((c) => {
              const variant = urgencyVariant(c);
              const isSent = sent[c.id];
              const pct = c.total > 0 ? Math.round(((c.total - c.missing) / c.total) * 100) : 100;
              return (
                <tr key={c.id} style={{ borderBottom: `1px solid ${tokens.border}`, background: selected?.id === c.id ? tokens.bg : tokens.surface, transition: "background 0.15s" }}>
                  <td style={{ padding: "10px 12px", fontWeight: 500 }}>
                    <div>{c.name}</div>
                    {c.assignedStaff && <div style={{ fontSize: 12, color: tokens.muted, marginTop: 2 }}>{c.assignedStaff}</div>}
                  </td>
                  <td style={{ padding: "10px 12px", textAlign: "center" }}>
                    <span style={{
                      display: "inline-block",
                      minWidth: 28,
                      padding: "2px 8px",
                      borderRadius: 99,
                      fontWeight: 700,
                      fontSize: 13,
                      background: c.missing > 0 ? (variant === "overdue" ? tokens.danger : "#f3ede8") : "#e8f5e9",
                      color: c.missing > 0 ? (variant === "overdue" ? "#fff" : "#7a4a1e") : "#2e7d32",
                    }}>{c.missing}</span>
                  </td>
                  <td style={{ padding: "10px 12px", minWidth: 120 }}>
                    <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
                      <div style={{ flex: 1, height: 6, background: tokens.border, borderRadius: 99, overflow: "hidden" }}>
                        <div style={{ width: `${pct}%`, height: "100%", background: pct === 100 ? "#4caf50" : tokens.accent, borderRadius: 99, transition: "width 0.3s" }}/>
                      </div>
                      <span style={{ fontSize: 12, color: tokens.muted, whiteSpace: "nowrap" }}>{c.total - c.missing}/{c.total}</span>
                    </div>
                  </td>
                  <td style={{ padding: "10px 12px", whiteSpace: "nowrap" }}>
                    {c.deadline ? (
                      <span style={{ color: c.daysLeft !== null && c.daysLeft <= 7 ? tokens.danger : tokens.text, fontWeight: c.daysLeft !== null && c.daysLeft <= 7 ? 600 : 400, fontSize: 13 }}>
                        {new Date(c.deadline).toLocaleDateString("en-US", { month: "short", day: "numeric" })}
                        <span style={{ marginLeft: 6, fontSize: 11, color: c.daysLeft !== null && c.daysLeft <= 7 ? tokens.danger : tokens.muted }}>
                          {daysLabel(c.daysLeft)}
                        </span>
                      </span>
                    ) : <span style={{ color: tokens.muted }}>—</span>}
                  </td>
                  <td style={{ padding: "10px 12px" }}>
                    <span style={{
                      display: "inline-flex", alignItems: "center", gap: 5,
                      padding: "3px 9px", borderRadius: 99, fontSize: 12, fontWeight: 500,
                      background: variant === "overdue" ? "#fdecea" : variant === "missing" ? "#fdf3ec" : "#f0f0f0",
                      color: variant === "overdue" ? tokens.danger : variant === "missing" ? "#b05a1a" : tokens.muted,
                    }}>
                      <span style={{ width: 6, height: 6, borderRadius: "50%", background: variant === "overdue" ? tokens.danger : variant === "missing" ? "#e07b30" : tokens.muted, display: "inline-block" }}/>
                      {variant === "overdue" ? "Deadline near" : variant === "missing" ? "Docs missing" : "On track"}
                    </span>
                  </td>
                  <td style={{ padding: "10px 12px", textAlign: "center" }}>
                    {isSent ? (
                      <span style={{ fontSize: 12, color: "#4caf50", fontWeight: 500 }}>Sent ✓</span>
                    ) : (
                      <button
                        onClick={() => open(c)}
                        style={{
                          padding: "5px 14px", borderRadius: tokens.radiusSm, border: `1px solid ${tokens.border}`,
                          background: selected?.id === c.id ? tokens.accent : tokens.surface,
                          color: selected?.id === c.id ? tokens.accentText : tokens.text,
                          fontFamily: tokens.font, fontSize: 13, cursor: "pointer", fontWeight: 500, transition: "all 0.15s",
                        }}
                      >
                        {selected?.id === c.id ? "Composing…" : "Chase"}
                      </button>
                    )}
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
      )}

      {selected && (
        <div style={{
          marginTop: 16, padding: 20, background: tokens.surface,
          border: `1px solid ${tokens.border}`, borderRadius: tokens.radiusMd,
          boxShadow: "0 2px 8px rgba(0,0,0,0.06)",
        }}>
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: 12 }}>
            <div>
              <div style={{ fontWeight: 600, fontSize: 15 }}>Message to {selected.name}</div>
              <div style={{ fontSize: 12, color: tokens.muted, marginTop: 2 }}>
                {selected.missing} document{selected.missing !== 1 ? "s" : ""} outstanding
                {selected.deadline ? ` · deadline ${new Date(selected.deadline).toLocaleDateString("en-US", { month: "short", day: "numeric" })}` : ""}
              </div>
            </div>
            <button onClick={close} style={{ background: "none", border: "none", cursor: "pointer", color: tokens.muted, fontSize: 18, lineHeight: 1, padding: 4 }}>×</button>
          </div>

          {phase === "awaiting" && (
            <div style={{ padding: "10px 14px", background: "#fdf8ec", border: "1px solid #f0d98a", borderRadius: tokens.radiusSm, fontSize: 13, color: "#7a5c00", marginBottom: 12 }}>
              Awaiting your approval before the message is sent.
            </div>
          )}
          {phase === "sent" && (
            <div style={{ padding: "10px 14px", background: "#edf7ed", border: "1px solid #a5d6a7", borderRadius: tokens.radiusSm, fontSize: 13, color: "#2e7d32", marginBottom: 12 }}>
              Message sent to {selected.name}.
            </div>
          )}

          {phase !== "sent" && (
            <>
              <textarea
                value={message}
                onChange={(e) => setMessage(e.target.value)}
                placeholder={`Hi ${selected.name?.split(" ")[0] || "there"}, we're still waiting on a few documents before we can file your return. Could you please upload them at your earliest convenience? Let us know if you have any questions.`}
                rows={4}
                style={{
                  width: "100%", boxSizing: "border-box", padding: "10px 12px",
                  border: `1px solid ${tokens.border}`, borderRadius: tokens.radiusSm,
                  fontFamily: tokens.font, fontSize: 14, color: tokens.text,
                  background: tokens.bg, resize: "vertical", outline: "none",
                  marginBottom: 10,
                }}
              />
              <div style={{ display: "flex", gap: 8, justifyContent: "flex-end" }}>
                <button onClick={close} style={{ padding: "7px 16px", borderRadius: tokens.radiusSm, border: `1px solid ${tokens.border}`, background: tokens.surface, color: tokens.text, fontFamily: tokens.font, fontSize: 13, cursor: "pointer" }}>
                  Cancel
                </button>
                <button
                  onClick={send}
                  disabled={!message.trim() || phase === "sending" || phase === "awaiting"}
                  style={{
                    padding: "7px 18px", borderRadius: tokens.radiusSm, border: "none",
                    background: !message.trim() || phase !== "idle" ? tokens.border : tokens.accent,
                    color: !message.trim() || phase !== "idle" ? tokens.muted : tokens.accentText,
                    fontFamily: tokens.font, fontSize: 13, fontWeight: 600,
                    cursor: !message.trim() || phase !== "idle" ? "not-allowed" : "pointer", transition: "all 0.15s",
                  }}
                >
                  {phase === "sending" ? "Sending…" : phase === "awaiting" ? "Awaiting approval…" : "Send message"}
                </button>
              </div>
            </>
          )}
        </div>
      )}
    </div>
  );
}
